{
  "name": "Weatherization Assistance Program",
  "eligibility": {
    "age": null,
    "income_limits": "Primarily tied to LIHEAP eligibility: at or below 60% of state median income for households of 1-8 members (specific table not fully detailed in sources; example for larger households at 150% FPL includes: 8 members $52,720 for LIHEAP/60% SMI, $85,194 for 150% FPL, $105,440 for Weatherization Only/200% FPL; 9: $58,100/$87,150/$116,200; 10: $63,480/$95,220/$126,960; scales up for larger sizes). 'Weatherization Only' for otherwise LIHEAP-qualified households up to 200% Federal Poverty Level (FPL). Households on SNAP, SSI, or TANF are automatically eligible. Annual recertification required.[1][2][3][4]",
    "asset_limits": "Resource limits apply (specific dollar amounts or exemptions not detailed in sources; income and resources considered together).[2][6]",
    "other_requirements": ["Must be LIHEAP eligible or qualify for 'Weatherization Only' (up to 200% FPL); home not previously weatherized; homeowners and renters eligible (requires owner/landlord signed access agreement DPHHS-EAP-013 for rentals); priority based on income, energy burden, vulnerable members (elderly, disabled, young children), home condition; U.S. citizen, qualified alien, or lawful permanent resident with SSN verification; tribal members use tribal LIHEAP priority.[1][2][3][4][5]"]
  },
  "benefits": {
    "type": "service",
    "value": "Energy efficiency improvements including insulation, air sealing, heating system repairs/replacements, other upgrades; energy education; potential utility discounts. No specific dollar cap or hours stated; prioritized by need.[1][3][4][5][7]",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Combined LIHEAP/Weatherization application (2025-2026 version available via local providers); phone (e.g., Action for Eastern Montana not specified, Human Resource Council 406-728-3710); mail/drop-off (e.g., Action for Eastern Montana: 2030 N. Merrill Ave, Glendive MT 59330); fax (e.g., 406-377-3571); local eligibility offices or tribal LIHEAP offices statewide; accepted Oct 1-Apr 30 for standard, anytime via local offices.[1][3][4][6][7]"],
    "processing_time": "Not specified; if approved but not in priority group, reapply after 1 year if no service.[4]",
    "waitlist": "Ranked into priority groups by need (special priority for elderly/disabled); priority list used, position checked via local provider.[1][3][4][5][7]",
    "forms": ["Combined LIHEAP and Weatherization application; DPHHS-EAP-013 Montana Weatherization Assistance Program(s) Access Agreement (for rentals).[1][3]"],
    "documents": ["Proof of income, resources, citizenship/qualified alien status/SSN; recent fuel/heat bill (auto-eligible for SNAP/SSI/TANF); signed access agreement for rentals.[1][2][3]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Administered via local sub-grantees, eligibility offices, and tribal programs; e.g., Action for Eastern Montana (17 eastern counties: Carter, Custer, Daniels, Dawson, Fallon, Garfield, McCone, Phillips, Powder River, Prairie, Richland, Roosevelt, Rosebud, Sheridan, Treasure, Valley, Wibaux); Human Resource Council; CAPNM; Action Inc. (Beaverhead, Deer Lodge, Granite, Madison, Powell, Silver Bow).[1][4][5][7][8]",
    "regional_variations": "Delivered by regional sub-grantees/local offices with potential differences in providers, contact points, and priority list management; tribal areas use tribal LIHEAP for priority.[1][2][3][4][7]",
    "offices_or_providers": ["Local Eligibility Offices (statewide list via dphhs.mt.gov); Tribal LIHEAP Offices; e.g., Action for Eastern Montana (Glendive), Human Resource Council (406-728-3710), CAPNM, Action Inc. Butte.[1][4][6][7][8]"]
  },
  "official_source": "https://dphhs.mt.gov/HCSD/energyassistance/WeatherizationAssistanceProgram",
  "gotchas": ["Must be LIHEAP eligible first (stricter than Weatherization Only at 200% FPL); priority-based waitlist means no guaranteed timeline—reapply after 1 year if not served; rentals need landlord signed access agreement; home must not have been previously weatherized; applications mainly Oct 1-Apr 30, but anytime via locals; regional sub-grantees required—must contact specific office for area; auto-eligibility for SNAP/SSI/TANF but still need application/bills.[1][3][4]"],
  "data_shape_notes": "Tied to LIHEAP with priority tiers by need/vulnerable members; regional sub-grantees handle delivery; 'Weatherization Only' tier up to 200% FPL; annual renewal; homeowner/renter with access agreement."
}

{
  "name": "State Health Insurance Assistance Program (SHIP)",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; open to all Medicare beneficiaries, their families, and caregivers, including those with limited incomes, under age 65 with disabilities, or dually eligible for Medicare and Medicaid[1][2]",
    "asset_limits": "No asset limits or tests apply[1]",
    "other_requirements": ["Must be a Medicare beneficiary, family member, or caregiver seeking counseling on Medicare-related issues[1][2]"]
  },
  "benefits": {
    "type": "service",
    "value": "Free, confidential one-on-one health-benefits counseling and advocacy including: Medicare eligibility/enrollment/benefits; Part D plan comparisons; related health insurance; Medigap; Medicare Health Plans; Medicare fraud/waste/abuse; long-term care options. Home visits for homebound individuals. Assistance applying for low-income programs like Medicaid, Medicare Savings Programs, Extra Help/Low Income Subsidy[1][2]",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: 1-800-551-3191 (statewide, connects to local counselor via Area Agency on Aging)[1]", "Phone: 406-444-4077 (state office)[3]", "In-person or home visit: Arranged via local Area Agency on Aging SHIP counselor after phone contact[1]", "Local examples: Roosevelt County (406-653-6221 or 406-653-6279), Richland County (406-433-3701)[4][5]"],
    "processing_time": "Immediate phone triage with referral to local counselor; appointment scheduling varies by local availability, no fixed statewide timeline specified[1]",
    "waitlist": null,
    "forms": ["No specific application forms required; counseling provided directly upon contact[1]"],
    "documents": ["No documents needed for initial counseling; bring Medicare card, current insurance details, prescriptions, or income info if seeking help with low-income programs like Extra Help[1][2]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; available to all Montana residents[1]",
    "regional_variations": "Operated through local Area Agencies on Aging with region-specific counselors and contact numbers; services consistent but access via local offices (e.g., Roosevelt, Richland Counties have dedicated counselors)[1][4][5]",
    "offices_or_providers": ["Administered by Montana Office on Aging via Area Agencies on Aging statewide; local examples include Roosevelt County SHIP Counselors and Richland County Council on Aging[1][4][5]"]
  },
  "official_source": "https://dphhs.mt.gov/SLTC/aging/SHIP[1]",
  "gotchas": ["Not affiliated with insurance companies and does not sell insurance—counselors provide objective advice only[1]", "Must call to be connected to local counselor; no central online application[1]", "Primarily for Medicare navigation, not direct financial aid or healthcare services[1][2]", "Homebound services available but require contacting local SHIP first[1]"],
  "data_shape_notes": "no income/asset test; counseling-only service delivered via decentralized local Area Agencies on Aging network; open to all Medicare beneficiaries/families without enrollment barriers"
}

{
  "name": "Legal Services for Seniors",
  "eligibility": {
    "age": 60,
    "income_limits": "No specific income limits mentioned; program targets low-income individuals but eligibility is determined by providers like Montana Legal Services Association (MLSA) based on household income, assets, citizenship status, and legal problem details. For related low-income legal aid via MLSA, screening includes income and assets without fixed dollar amounts provided[8][10].",
    "asset_limits": "Assets considered in screening by MLSA, but no specific dollar limits or exemptions detailed[8][10].",
    "other_requirements": ["Montana resident", "Low-income status (screened case-by-case)", "Civil legal issues related to aging, disability, or estate planning", "For some providers like MLSA, U.S. citizenship or eligible immigration status"]
  },
  "benefits": {
    "type": "service",
    "value": "Free legal advice clinics, telephone consultations, help drafting/reviewing/notarizing estate planning documents (wills, powers of attorney, transfer deeds, living wills, health care power of attorney, declaration of homestead), referrals to legal/advocacy organizations, training/education for seniors/caregivers/professionals, annual estate planning clinics statewide. Services limited to basic estate planning; does not cover complex estates, large assets, or trusts[4].",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Online application via Montana Legal Services Association (MLSA) at montanalawhelp.org/apply-legal-services or mtlawhelp.org/apply-legal-services[8][10]", "Phone: MLSA Helpline 1-800-666-6899 (Tue-Thu 9am-1pm MT); Legal Services Developer Program 1-800-332-2272[8][9]", "In-person: Statewide legal document clinics hosted by Montana Aging Services Bureau (locations vary, check DPHHS for schedule)[4]", "Mail: Not specified, but online/phone lead to intake"],
    "processing_time": "MLSA: Expect callback in 3-5 business days; urgent deadlines noted on application get priority[8].",
    "waitlist": "High call volume may cause delays; keep trying phone or use online form[8].",
    "forms": ["Online application form (MLSA, 10-15 minutes, asks income/assets/legal issue)[8][10]", "Statutory forms: Declaration of Living Will, Health Care Power of Attorney, Simple Will (single/married), Financial Power of Attorney, Transfer on Death Deed (provided at clinics)[4]"],
    "documents": ["Proof of income/assets/household size (for screening)", "ID/proof of Montana residency/citizenship", "Details of legal problem", "For clinics: No advance docs needed, but bring personal info for drafting"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Montana residents age 60+ or adults with disabilities; enrolled tribal members eligible for clinics[4].",
    "regional_variations": "Annual estate planning clinics held statewide with local networks of attorneys/notaries/law students/volunteers; community programs may differ slightly in services[4][7].",
    "offices_or_providers": ["Montana Department of Public Health and Human Services (DPHHS) Office on Aging", "Montana Legal Services Association (MLSA)", "Montana Aging Services Bureau clinics", "Area Agencies on Aging (local via Eldercare Locator 800-677-1116)[4][7][8]"]
  },
  "official_source": "https://dphhs.mt.gov/sltc/aging/legal/",
  "gotchas": ["Services limited to basic estate planning only—no complex estates, large assets, trusts, or non-civil matters[4]", "Simple statutory forms may not suit all situations; consult licensed attorney for complex needs[4]", "High phone volume at MLSA; use online form if can't get through[8]", "Individuals under 60 directed to MLSA or State Bar, not this program[4]", "No compensation allowed for emeritus attorneys in related pro bono (separate program)[2]"],
  "data_shape_notes": "No fixed income/asset limits—case-by-case screening; statewide clinics but local variation in scheduling/providers; focuses on free basic estate planning docs, not full representation or complex cases"
}

{
  "name": "Long-Term Care Ombudsman Program",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; open to all regardless of financial status.",
    "asset_limits": "No asset limits; no financial tests apply.",
    "other_requirements": ["Resident of a nursing home, assisted living facility, or Critical Access Hospital (including swing beds) in Montana.", "Or family member, friend, staff, or any concerned individual on behalf of such a resident."]
  },
  "benefits": {
    "type": "advocacy",
    "value": "Investigation and resolution of complaints related to resident rights, quality of care/life, administrative decisions, Medicaid/Medicare/long-term care programs, improper transfer/discharge, abuse/neglect/exploitation, and quality of life/well-being. Provides information on long-term care issues/services/placement options, referrals to aging services, assistance for staff, public education, advocacy for legislation/policies, and promotion of resident/family councils. All contacts confidential; services at resident's request.",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: 1-800-332-2272 (State Long Term Care Ombudsman, business hours only; emergencies call 911).", "Local Ombudsman via Area Agencies on Aging or County Councils on Aging (statewide directory at https://dphhs.mt.gov/sltc/aging/longtermcareombudsman/).", "Mail: Montana Senior and Long Term Care, PO Box 4210, Helena, MT 59604.", "In-person: Local ombudsman offices through Area Agencies on Aging."],
    "processing_time": "Immediate response to complaints; ombudsmen move into action at resident's request.",
    "waitlist": null,
    "forms": ["No specific forms required; contact directly to report concerns."],
    "documents": ["No documents needed to initiate contact; provide details of the concern verbally or in writing."]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Limited to residents in long-term care facilities (nursing homes, assisted living, Critical Access Hospitals with swing beds) across Montana.",
    "regional_variations": "Over 30 certified ombudsmen employed by Area Agencies on Aging or County Councils on Aging; local ombudsmen handle investigations regionally, with regular facility visits.",
    "offices_or_providers": ["State office in Helena; local via Area Agencies on Aging (e.g., Western Montana Area VI Agency, Flathead County Agency on Aging). Directory: https://dphhs.mt.gov/sltc/aging/longtermcareombudsman/."]
  },
  "official_source": "https://dphhs.mt.gov/sltc/aging/longtermcareombudsman/",
  "gotchas": ["Not a healthcare or financial benefits program—purely advocacy and complaint resolution; no direct services like personal care or funding.", "Help line business hours only (not 24/7); for emergencies, call 911.", "Must be for residents in certified long-term care facilities—does not cover home-based or independent living.", "Ombudsmen act at resident's request and maintain confidentiality; family cannot override resident wishes.", "Separate from Mental Health Ombudsman or Child and Family Ombudsman."],
  "data_shape_notes": "no income/asset/age test; advocacy-only for facility residents statewide via local ombudsmen; open to anyone on behalf of resident"
}
